import React, { useEffect, useMemo, useState } from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import AdminSidebar from "../components/AdminSidebar";
import { getAdminMatches } from "../services/api";
import { formatDateTimeVN } from "../utils/format";

function AdminMatches() {
  const [matches, setMatches] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    const fetchMatches = async () => {
      try {
        const data = await getAdminMatches();
        setMatches(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchMatches();
  }, []);

  const filtered = useMemo(() => {
    if (!search.trim()) return matches;
    const q = search.toLowerCase();
    return matches.filter(
      (m) =>
        (m.title || "").toLowerCase().includes(q) ||
        (m.location || "").toLowerCase().includes(q) ||
        String(m.id).includes(q)
    );
  }, [matches, search]);

  return (
    <div>
      <Navbar />

      <div className="container page-section admin-page-layout">
        <AdminSidebar />

        <div className="admin-page-main">
          <div className="match-page-head">
            <div>
              <span className="page-badge">⚽ Quản lý trận đấu</span>
              <h1 className="section-title" style={{ marginTop: "10px" }}>Quản lý trận đấu</h1>
              <p className="section-subtitle">
                Theo dõi danh sách các trận đấu hiện có trong hệ thống.
              </p>
            </div>
          </div>

          <div className="admin-stat-grid" style={{ gridTemplateColumns: "repeat(2,1fr)" }}>
            <div className="admin-stat-card admin-stat-green">
              <div className="admin-stat-icon">⚽</div>
              <div className="admin-stat-body">
                <span className="admin-stat-label">Tổng trận đấu</span>
                <strong className="admin-stat-value">{matches.length}</strong>
                <span className="admin-stat-sub">Trong hệ thống</span>
              </div>
            </div>
            <div className="admin-stat-card admin-stat-blue">
              <div className="admin-stat-icon">🔍</div>
              <div className="admin-stat-body">
                <span className="admin-stat-label">Kết quả tìm kiếm</span>
                <strong className="admin-stat-value">{filtered.length}</strong>
                <span className="admin-stat-sub">Trận đang hiển thị</span>
              </div>
            </div>
          </div>

          <div className="match-toolbar" style={{ marginBottom: "18px" }}>
            <div className="match-search-box">
              <input
                type="text"
                placeholder="🔍 Tìm theo tên trận, địa điểm..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
          </div>

          {loading && (
            <div className="loading-state">
              <div className="loading-spinner"></div>
              <p>Đang tải dữ liệu trận đấu...</p>
            </div>
          )}
          {error && <p className="error-text">{error}</p>}

          {!loading && !error && filtered.length === 0 && (
            <div className="empty-box">
              {search ? "Không tìm thấy trận phù hợp." : "Hiện chưa có trận đấu nào trong hệ thống."}
            </div>
          )}

          {!loading && !error && filtered.length > 0 && (
            <div className="table-wrap">
              <div className="table-wrap-header">
                <h3>Danh sách trận đấu ({filtered.length})</h3>
              </div>
              <table>
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Tên trận</th>
                    <th>Địa điểm</th>
                    <th>Thời gian</th>
                    <th>Sức chứa</th>
                    <th>Booking ID</th>
                    <th>Trạng thái</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((match) => (
                    <tr key={match.id}>
                      <td><strong>#{match.id}</strong></td>
                      <td>
                        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                          <span style={{ fontSize: "18px" }}>⚽</span>
                          <span style={{ fontWeight: 700 }}>{match.title}</span>
                        </div>
                      </td>
                      <td>📍 {match.location || "—"}</td>
                      <td>{formatDateTimeVN(match.time) || match.time || "—"}</td>
                      <td>
                        <span style={{ fontWeight: 700 }}>{match.max_players || "—"}</span>
                        {match.max_players && <span style={{ color: "#66756d" }}> người</span>}
                      </td>
                      <td>{match.booking_id ? `#${match.booking_id}` : "—"}</td>
                      <td>
                        <span className="status-badge status-confirmed">Đang mở</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default AdminMatches;
